#!/usr/bin/env python3\n\"\"\"\nAngel One Integration Verification Script\nVerifies that all components are properly configured\n\"\"\"\n\nimport os\nimport sys\nfrom pathlib import Path\n\ndef print_header(text):\n    print(f\"\\n{'='*60}\")\n    print(f\"  {text}\")\n    print(f\"{'='*60}\")\n\ndef check_file_exists(filepath, description):\n    if Path(filepath).exists():\n        print(f\"✅ {description}: {filepath}\")\n        return True\n    else:\n        print(f\"❌ {description}: {filepath} (NOT FOUND)\")\n        return False\n\ndef check_env_vars():\n    print_header(\"Environment Variables Check\")\n    \n    env_path = Path('.env')\n    if not env_path.exists():\n        print(\"❌ .env file not found\")\n        print(\"   Create .env file with Angel One credentials:\")\n        print(\"   - ANGEL_ONE_CLIENT_ID\")\n        print(\"   - ANGEL_ONE_API_KEY\")\n        print(\"   - ANGEL_ONE_PASSWORD\")\n        print(\"   - ANGEL_ONE_TOTP\")\n        print(\"   - NEWSAPI_KEY\")\n        return False\n    \n    required_vars = [\n        'ANGEL_ONE_CLIENT_ID',\n        'ANGEL_ONE_API_KEY',\n        'ANGEL_ONE_PASSWORD',\n        'ANGEL_ONE_TOTP',\n        'NEWSAPI_KEY'\n    ]\n    \n    # Try loading from .env\n    try:\n        from dotenv import load_dotenv\n        load_dotenv()\n        \n        missing = []\n        for var in required_vars:\n            if os.getenv(var):\n                print(f\"✅ {var}: configured\")\n            else:\n                print(f\"❌ {var}: not configured\")\n                missing.append(var)\n        \n        if missing:\n            print(f\"\\n⚠️  Missing {len(missing)} environment variables\")\n            return False\n        return True\n    except Exception as e:\n        print(f\"❌ Error reading .env: {e}\")\n        return False\n\ndef check_dependencies():\n    print_header(\"Python Dependencies Check\")\n    \n    required_packages = [\n        ('flask', 'Flask'),\n        ('pandas', 'pandas'),\n        ('numpy', 'numpy'),\n        ('sklearn', 'scikit-learn'),\n        ('requests', 'requests'),\n        ('dotenv', 'python-dotenv'),\n        ('xgboost', 'xgboost'),\n        ('lightgbm', 'lightgbm'),\n        ('tensorflow', 'tensorflow'),\n        ('smartapi', 'smartapi-python'),\n        ('pyotp', 'pyotp')\n    ]\n    \n    missing = []\n    for import_name, package_name in required_packages:\n        try:\n            __import__(import_name)\n            print(f\"✅ {package_name}\")\n        except ImportError:\n            print(f\"❌ {package_name}\")\n            missing.append(package_name)\n    \n    if missing:\n        print(f\"\\n⚠️  Missing {len(missing)} packages\")\n        print(\"\\nInstall with:\")\n        print(\"  pip install -r requirements.txt\")\n        return False\n    return True\n\ndef check_frontend_files():\n    print_header(\"Frontend Files Check\")\n    \n    files = [\n        ('../frontend/index.html', 'Main HTML file'),\n        ('../frontend/script.js', 'Main JavaScript'),\n        ('../frontend/angel_one.js', 'Angel One module'),\n        ('../frontend/styles.css', 'CSS styles'),\n        ('../frontend/spa-tabs.js', 'SPA navigation')\n    ]\n    \n    all_exist = True\n    for filepath, description in files:\n        if not check_file_exists(filepath, description):\n            all_exist = False\n    \n    return all_exist\n\ndef check_backend_files():\n    print_header(\"Backend Files Check\")\n    \n    files = [\n        ('app.py', 'Main Flask application'),\n        ('angel_one_api.py', 'Angel One API wrapper'),\n        ('requirements.txt', 'Python dependencies'),\n        ('.env.example', 'Environment template')\n    ]\n    \n    all_exist = True\n    for filepath, description in files:\n        if not check_file_exists(filepath, description):\n            all_exist = False\n    \n    return all_exist\n\ndef check_angel_one_module():\n    print_header(\"Angel One Module Check\")\n    \n    try:\n        from angel_one_api import AngelOneAPI\n        print(\"✅ Angel One API module loads successfully\")\n        print(\"   - Class: AngelOneAPI\")\n        print(\"   - Methods: authenticate, get_quote, get_portfolio, get_orderbook\")\n        return True\n    except Exception as e:\n        print(f\"❌ Failed to load Angel One module: {e}\")\n        return False\n\ndef check_flask_endpoints():\n    print_header(\"Flask Endpoints Check\")\n    \n    endpoints = [\n        '/angel-status',\n        '/angel-quotes',\n        '/angel-portfolio',\n        '/angel-orderbook',\n        '/news',\n        '/history',\n        '/prediction'\n    ]\n    \n    try:\n        # Try to read app.py and check for routes\n        with open('app.py', 'r') as f:\n            content = f.read()\n            \n        all_found = True\n        for endpoint in endpoints:\n            if endpoint in content:\n                print(f\"✅ {endpoint} endpoint configured\")\n            else:\n                print(f\"❌ {endpoint} endpoint NOT found\")\n                all_found = False\n        \n        return all_found\n    except Exception as e:\n        print(f\"❌ Error checking endpoints: {e}\")\n        return False\n\ndef main():\n    print(\"\\n\" + \"=\"*60)\n    print(\"  Angel One Integration Verification\")\n    print(\"  Status: PRE-DEPLOYMENT CHECK\")\n    print(\"=\"*60)\n    \n    checks = [\n        ('Backend Files', check_backend_files),\n        ('Frontend Files', check_frontend_files),\n        ('Python Dependencies', check_dependencies),\n        ('Angel One Module', check_angel_one_module),\n        ('Flask Endpoints', check_flask_endpoints),\n        ('Environment Variables', check_env_vars)\n    ]\n    \n    results = {}\n    for name, check_func in checks:\n        try:\n            results[name] = check_func()\n        except Exception as e:\n            print(f\"\\n❌ Error during {name}: {e}\")\n            results[name] = False\n    \n    # Summary\n    print_header(\"Verification Summary\")\n    \n    passed = sum(1 for v in results.values() if v)\n    total = len(results)\n    \n    for name, result in results.items():\n        status = \"✅ PASS\" if result else \"❌ FAIL\"\n        print(f\"{status}: {name}\")\n    \n    print(f\"\\nResult: {passed}/{total} checks passed\")\n    \n    if passed == total:\n        print(\"\\n🎉 All checks passed! Ready to deploy.\")\n        print(\"\\nNext steps:\")\n        print(\"  1. Start backend: python app.py\")\n        print(\"  2. Open frontend: http://localhost:5000\")\n        print(\"  3. Go to Angel One section in navbar\")\n        return 0\n    else:\n        print(f\"\\n⚠️  {total - passed} check(s) failed. Please fix above issues.\")\n        return 1\n\nif __name__ == '__main__':\n    # Change to backend directory\n    backend_path = Path(__file__).parent / 'backend'\n    if backend_path.exists():\n        os.chdir(backend_path)\n    \n    sys.exit(main())\n